using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class ShipmentsTraining : TrainingContentBase
{
    public ShipmentsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Shipments Overview",
            Slug = "shipments-overview",
            Summary = "What shipments are, the shipment lifecycle, line items, and how shipments connect to sales orders and invoices.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/shipments"]""",
            Tags = """["shipments","shipping"]""",
            ContentJson = """{"body":"## Shipments Overview\n\nThe Shipments module tracks every outbound shipment from your shop. Each shipment is tied to a Sales Order and contains one or more line items that describe what is being shipped, in what quantity. Shipments move through a defined lifecycle from creation to delivery, and they connect directly to invoicing so you always know what has been shipped and billed.\n\n### What Is a Shipment?\n\nA shipment represents a physical package or set of packages leaving your facility to fulfill (or partially fulfill) a Sales Order. Each shipment has:\n- A unique **Shipment Number** (auto-generated)\n- A link to exactly one **Sales Order**\n- One or more **Line Items** specifying parts and quantities\n- Optional **Carrier** and **Tracking Number** for logistics\n- Optional **Weight** and **Shipping Cost** for record-keeping\n- A **Status** indicating where the shipment is in its lifecycle\n\n### Shipment Lifecycle\n\nShipments follow a linear status progression:\n\n1. **Pending** — Shipment has been created but nothing has been packed yet. This is the initial status for all new shipments.\n2. **Packed** — Items have been physically packed and are ready to ship. The shipment is waiting for carrier pickup or drop-off.\n3. **Shipped** — The shipment has left your facility. The shipped date is recorded automatically when you mark it shipped.\n4. **In Transit** — The carrier has the shipment and it is en route to the customer. Tracking information updates are available if a tracking number is provided.\n5. **Delivered** — The shipment has been received by the customer. The delivered date is recorded automatically.\n6. **Cancelled** — The shipment was cancelled before delivery. Cancelled shipments are preserved for audit purposes.\n\nYou can move a shipment forward through statuses using the action buttons in the detail view. Shipments can be marked shipped from either Pending or Packed status, and marked delivered from either Shipped or In Transit status.\n\n### Line Items\n\nEach shipment line references a Part from your Parts Catalog and a quantity. Lines can optionally link to a specific Sales Order Line to track partial fulfillment. When you create a shipment, you select a Sales Order first, then add parts and quantities. A single Sales Order can have multiple shipments (partial deliveries), and each shipment tracks exactly which items and quantities were included.\n\n### How Shipments Connect to Other Features\n\n**Sales Orders:** Every shipment belongs to one Sales Order. The Sales Order tracks overall fulfillment across all its shipments. You can see the linked Sales Order directly from the shipment detail view.\n\n**Invoices:** After a shipment is shipped, it can be linked to an Invoice. The shipment detail view shows the linked invoice when one exists, providing a clear audit trail from order to shipment to billing.\n\n**Customers:** The customer name and shipping address flow from the Sales Order. The shipment detail view shows the customer name and allows navigation to the Sales Order for full order context.\n\n**Carrier Integration:** The system supports carrier rate comparison and label generation. From the shipment detail, you can request shipping rates from configured carriers, compare options, and create a shipping label — all without leaving QB Engineer.\n\n**Tracking:** When a tracking number is entered (manually or via label creation), you can view the tracking timeline directly in the shipment detail. The timeline shows each tracking event with location, status, and timestamp.\n\n**Packing Slip PDF:** Every shipment can generate a printable packing slip that includes the shipment number, customer information, shipping address, and a table of all line items with quantities. This is useful for including in the physical package.\n\n### When to Use Shipments\n\n- When fulfilling a Sales Order — create a shipment to record what is being sent\n- When shipping partial orders — create multiple shipments against the same Sales Order\n- When you need carrier rate comparison before choosing a shipping method\n- When you need tracking visibility for outbound packages\n- When generating packing slips to include with shipments\n- When you need an audit trail connecting orders, shipments, and invoices","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Shipments — Guided Tour",
            Slug = "shipments-walkthrough",
            Summary = "A guided tour of the shipments list page: search, filters, data table, creating shipments, and viewing shipment details.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/shipments"]""",
            Tags = """["shipments","shipping","walkthrough"]""",
            ContentJson = """{"appRoute":"/shipments","startButtonLabel":"Tour Shipments","steps":[{"element":"[data-testid='new-shipment-btn']","popover":{"title":"New Shipment Button","description":"Click here to create a new shipment. You'll select a Sales Order, add line items with parts and quantities, and optionally enter carrier and tracking information. The dialog uses a split layout: line items on the left, shipment details and notes on the right.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Shipments","description":"Search by shipment number, Sales Order number, customer name, carrier, or tracking number. Press Enter to apply the search. Results update in the table below.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Status Filter","description":"Filter shipments by their current status: Pending, Packed, Shipped, In Transit, Delivered, or Cancelled. Each status has a distinct color-coded chip in the table for quick identification.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Shipments Table","description":"Click any row to open the shipment detail dialog. Columns include Shipment Number, SO Number, Customer, Status (color chip), Carrier, Tracking Number, Shipped Date, and Created date. Click column headers to sort. Use the gear icon to manage column visibility and order.","side":"top"}},{"element":"[data-testid='new-shipment-btn']","popover":{"title":"Creating a Shipment — Walkthrough","description":"When you click New Shipment, a dialog opens with a split layout. On the left, you manage line items: select a part from the autocomplete dropdown, enter a quantity, and click Add. Each line appears in a table where you can remove it. On the right sidebar, select the Sales Order (required), and optionally enter Carrier, Tracking Number, Weight, Shipping Cost, and Notes. Save is disabled until you have at least one line item and a Sales Order selected.","side":"left"}},{"element":"app-data-table","popover":{"title":"Shipment Detail View","description":"Clicking a row opens the detail dialog. It shows the shipment number, status chip, linked Sales Order (clickable), customer name, carrier info, tracking number, shipped/delivered dates, weight, shipping cost, notes, and all line items. Action buttons appear based on status: Mark Shipped (from Pending/Packed), Get Rates (carrier rate comparison), Track (loads tracking timeline), and Mark Delivered (from Shipped/In Transit). An activity timeline shows the full history of status changes and updates.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Shipments Field Reference",
            Slug = "shipments-field-reference",
            Summary = "Complete reference for every field, button, status, validation rule, and action in the Shipments module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/shipments"]""",
            Tags = """["shipments","shipping","reference"]""",
            ContentJson = """{"title":"Shipments Field Reference","groups":[{"heading":"Shipment Form Fields (Create Dialog — Sidebar)","items":[{"label":"Sales Order (required)","value":"Autocomplete dropdown. Select the Sales Order this shipment fulfills. Displays as 'OrderNumber — CustomerName (CustomerPO)'. This is the only required field on the sidebar. data-testid: shipment-so"},{"label":"Carrier","value":"Text input, optional. The shipping carrier name (e.g., 'UPS', 'FedEx', 'USPS', 'DHL', 'Freight'). Displayed in the table and detail view. data-testid: shipment-carrier"},{"label":"Tracking Number","value":"Text input, optional. The carrier-provided tracking number. When present, enables the Track button in the detail view to load tracking timeline. data-testid: shipment-tracking"},{"label":"Weight","value":"Number input, optional. Total shipment weight in pounds. Displayed in detail view with 'lbs' suffix. data-testid: shipment-weight"},{"label":"Shipping Cost","value":"Number input, optional. Total shipping cost in dollars. Displayed in detail view formatted as currency. data-testid: shipment-cost"},{"label":"Notes","value":"Textarea, optional. Free-form notes about the shipment (special handling instructions, delivery notes, etc.). 3 rows. data-testid: shipment-notes"}]},{"heading":"Line Item Fields (Create Dialog — Main Area)","items":[{"label":"Part (required)","value":"Autocomplete dropdown. Select a part from the Parts Catalog (only Active parts shown). Displays as 'PartNumber — Description'. Each line must have a part selected."},{"label":"Quantity (required)","value":"Number input. Must be at least 1. Defaults to 1 when adding a new line. data-testid: shipment-line-qty"},{"label":"Add button","value":"Adds the selected part and quantity as a new line item. Disabled when line form is invalid (no part selected or quantity < 1)."},{"label":"Remove button (X)","value":"Removes a line item from the shipment. Each line in the table has a red X button to remove it."}]},{"heading":"Shipment Statuses","items":[{"label":"Pending (gray chip)","value":"Initial status. Shipment has been created but items are not yet packed. Can be marked shipped directly or moved to Packed first."},{"label":"Packed (blue/info chip)","value":"Items have been packed and the shipment is ready to leave the facility. Can be marked shipped from this status."},{"label":"Shipped (primary chip)","value":"Shipment has left the facility. Shipped date is recorded automatically. Can be marked delivered from this status."},{"label":"In Transit (yellow/warning chip)","value":"Carrier has the shipment and it is en route. Can be marked delivered from this status. Tracking timeline shows carrier updates."},{"label":"Delivered (green/success chip)","value":"Customer has received the shipment. Delivered date is recorded automatically. Terminal status — no further actions available."},{"label":"Cancelled (red/error chip)","value":"Shipment was cancelled before delivery. Record is preserved for audit. Terminal status — no further actions available."}]},{"heading":"Detail View Fields (Read-Only)","items":[{"label":"Shipment Number","value":"Auto-generated unique identifier. Displayed prominently at the top of the detail view with a shipping icon."},{"label":"Customer Name","value":"Pulled from the linked Sales Order. Shown as a subtitle under the shipment number."},{"label":"Sales Order","value":"Clickable entity link that opens the Sales Order detail dialog. Shows the SO number."},{"label":"Carrier","value":"Shown only if a carrier was entered. Text display."},{"label":"Tracking Number","value":"Shown only if entered. Displayed in monospace font for readability. Enables the Track button."},{"label":"Shipped Date","value":"Shown only after marking shipped. Formatted as MM/dd/yyyy."},{"label":"Delivered Date","value":"Shown only after marking delivered. Formatted as MM/dd/yyyy."},{"label":"Weight","value":"Shown only if entered. Displayed with 'lbs' suffix."},{"label":"Shipping Cost","value":"Shown only if entered. Formatted as currency (e.g., $25.00)."},{"label":"Linked Invoice","value":"Shown only if an invoice has been generated for this shipment. Clickable entity link to the invoice detail."},{"label":"Notes","value":"Shown only if notes were entered. Free-form text block."},{"label":"Line Items","value":"Table showing description and quantity for each line. Header shows count (e.g., 'Line Items (3)')."},{"label":"Created At / Updated At","value":"Timestamps at the bottom of the detail view. Formatted as MM/dd/yyyy."}]},{"heading":"Buttons and Actions","items":[{"label":"New Shipment (primary button, page header)","value":"Opens the create shipment dialog. data-testid: new-shipment-btn"},{"label":"Save / Create Shipment (dialog footer)","value":"Creates the shipment. Disabled when form is invalid, no lines exist, or save is in progress. Validation popover shows violations on hover. data-testid: shipment-save-btn"},{"label":"Cancel (dialog footer)","value":"Closes the create dialog without saving."},{"label":"Mark Shipped (detail view)","value":"Transitions status to Shipped and records the shipped date. Available when status is Pending or Packed. Shows a confirmation dialog before proceeding."},{"label":"Mark Delivered (detail view)","value":"Transitions status to Delivered and records the delivered date. Available when status is Shipped or In Transit. Shows a confirmation dialog before proceeding."},{"label":"Get Rates (detail view)","value":"Opens the shipping rates dialog to compare carrier rates. Available when status is Pending or Packed. Shows rates from configured carriers with service level, price, and estimated delivery."},{"label":"Track (detail view)","value":"Loads the tracking timeline for the shipment. Available when a tracking number exists and the timeline is not already displayed. Shows tracking events with location, status, and timestamp."},{"label":"Close Tracking (detail view)","value":"Collapses the tracking timeline panel."},{"label":"Row Click (table)","value":"Opens the shipment detail dialog for the clicked row. Shows all shipment information, line items, tracking, and available actions."}]},{"heading":"Validation Rules","items":[{"label":"Sales Order","value":"Required. Must select a valid Sales Order from the autocomplete dropdown."},{"label":"Line Items","value":"At least one line item is required. The Save button is disabled and a validation message appears if no lines are present."},{"label":"Part (per line)","value":"Required. Must select a valid part from the autocomplete."},{"label":"Quantity (per line)","value":"Required. Must be at least 1."},{"label":"Carrier, Tracking Number, Weight, Shipping Cost, Notes","value":"All optional. No format restrictions."},{"label":"Submit button popover","value":"When form is invalid or no lines exist, hovering over the Save button shows a validation popover listing all violations."}]},{"heading":"Table Columns","items":[{"label":"Shipment #","value":"Sortable. Width: 120px. Auto-generated shipment number displayed in monospace font."},{"label":"SO #","value":"Sortable. Width: 120px. The linked Sales Order number displayed in monospace font."},{"label":"Customer","value":"Sortable. Customer name from the linked Sales Order."},{"label":"Status","value":"Sortable, filterable (enum). Width: 120px. Color-coded chip: Pending (gray), Packed (blue), Shipped (primary), In Transit (yellow), Delivered (green), Cancelled (red)."},{"label":"Carrier","value":"Sortable. Width: 100px. Carrier name or '---' if not set."},{"label":"Tracking #","value":"Sortable. Width: 140px. Tracking number in monospace font or '---' if not set."},{"label":"Shipped Date","value":"Sortable. Width: 110px. Date type. Formatted as MM/dd/yyyy or '---' if not yet shipped."},{"label":"Created","value":"Sortable. Width: 110px. Date type. Record creation date formatted as MM/dd/yyyy."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Shipments Knowledge Check",
            Slug = "shipments-quiz",
            Summary = "Test your knowledge of the Shipments module: statuses, line items, carrier integration, tracking, and workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/shipments"]""",
            Tags = """["shipments","shipping","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"sh1","text":"A customer's Sales Order is ready to ship. What is the first step to record the outbound shipment in QB Engineer?","options":[{"id":"a","text":"Go to Sales Orders and click a Ship button on the order"},{"id":"b","text":"Navigate to Shipments, click New Shipment, select the Sales Order, add line items with parts and quantities, then save","isCorrect":true},{"id":"c","text":"Go to Inventory and create a bin movement to remove the items from stock"},{"id":"d","text":"Create an Invoice first and the shipment is generated automatically"}],"explanation":"Shipments are created from the Shipments page. Click New Shipment, select the Sales Order from the autocomplete, add the parts and quantities being shipped as line items, and save. The shipment starts in Pending status."},{"id":"sh2","text":"What is the correct order of shipment statuses from creation to completion?","options":[{"id":"a","text":"Draft → Packed → Shipped → Delivered"},{"id":"b","text":"Pending → Packed → Shipped → In Transit → Delivered","isCorrect":true},{"id":"c","text":"Open → Processing → Shipped → Closed"},{"id":"d","text":"Created → Ready → Out for Delivery → Complete"}],"explanation":"The shipment lifecycle is: Pending (created) → Packed (items ready) → Shipped (left facility) → In Transit (carrier has it) → Delivered (customer received). Not every shipment passes through all statuses — you can skip from Pending directly to Shipped."},{"id":"sh3","text":"You have a Sales Order with 100 units but the customer wants 50 shipped now and 50 later. How do you handle this?","options":[{"id":"a","text":"You cannot split shipments — the entire Sales Order must ship at once"},{"id":"b","text":"Create two separate shipments against the same Sales Order, each with 50 units","isCorrect":true},{"id":"c","text":"Edit the Sales Order to reduce it to 50, then create a second Sales Order for the remaining 50"},{"id":"d","text":"Ship all 100 and mark 50 as backordered in the notes"}],"explanation":"A single Sales Order can have multiple shipments (partial deliveries). Create the first shipment with 50 units, then later create a second shipment with the remaining 50 units — both linked to the same Sales Order."},{"id":"sh4","text":"A shipment is currently in Pending status. Which actions are available in the detail view?","options":[{"id":"a","text":"Only Mark Delivered"},{"id":"b","text":"Mark Shipped and Get Rates","isCorrect":true},{"id":"c","text":"Mark Shipped, Get Rates, Mark Delivered, and Track"},{"id":"d","text":"No actions — you must edit the shipment first"}],"explanation":"From Pending (or Packed) status, two actions are available: Mark Shipped (transitions to Shipped and records the date) and Get Rates (opens carrier rate comparison dialog). Mark Delivered is only available from Shipped or In Transit status. Track is available whenever a tracking number exists."},{"id":"sh5","text":"What is required to save a new shipment?","options":[{"id":"a","text":"Only a Sales Order selection"},{"id":"b","text":"A Sales Order selection and at least one line item with a part and quantity","isCorrect":true},{"id":"c","text":"A Sales Order, carrier, and tracking number"},{"id":"d","text":"A Sales Order, line items, carrier, tracking number, and weight"}],"explanation":"Two things are required: a Sales Order must be selected (the only required sidebar field), and at least one line item must be added (each line needs a part and a quantity of at least 1). Carrier, tracking number, weight, shipping cost, and notes are all optional."},{"id":"sh6","text":"You want to compare shipping rates from different carriers before shipping. Where do you do this?","options":[{"id":"a","text":"Go to Admin → Shipping → Rate Calculator"},{"id":"b","text":"Open the shipment detail (click the row), then click Get Rates to open the rate comparison dialog","isCorrect":true},{"id":"c","text":"Navigate to the linked Sales Order and use its shipping tab"},{"id":"d","text":"Rates are not available in QB Engineer — you must check carrier websites separately"}],"explanation":"In the shipment detail view, click the Get Rates button (available when status is Pending or Packed). This opens a dialog showing rates from configured carriers with service level, price, and estimated delivery time. You can create a shipping label directly from this dialog."},{"id":"sh7","text":"A shipment has a tracking number entered. How do you view the tracking timeline?","options":[{"id":"a","text":"Go to the carrier's website and paste the tracking number"},{"id":"b","text":"Open the shipment detail and click the Track button to load the tracking timeline directly in QB Engineer","isCorrect":true},{"id":"c","text":"Tracking timelines are only available for shipments with carrier API integration enabled"},{"id":"d","text":"Navigate to Admin → Tracking to look up any tracking number"}],"explanation":"When a tracking number is present, a Track button appears in the shipment detail view. Click it to load the tracking timeline, which shows each tracking event with location, status, and timestamp — all within QB Engineer. Click the close button to collapse the timeline."},{"id":"sh8","text":"What happens when you click Mark Shipped on a shipment?","options":[{"id":"a","text":"The shipment is immediately deleted and an invoice is created"},{"id":"b","text":"A confirmation dialog appears, and if confirmed, the status changes to Shipped and the shipped date is recorded automatically","isCorrect":true},{"id":"c","text":"The status changes without confirmation and you must manually enter the shipped date"},{"id":"d","text":"An email is automatically sent to the customer with the tracking number"}],"explanation":"Clicking Mark Shipped opens a confirmation dialog. If you confirm, the status transitions to Shipped and the shipped date is automatically set to the current date. A success snackbar confirms the action. The customer is not automatically notified."},{"id":"sh9","text":"Where can you see which invoice is linked to a shipment?","options":[{"id":"a","text":"In the Sales Order detail under the Shipments tab"},{"id":"b","text":"In the shipment detail view — a Linked Invoice field appears with a clickable link to the invoice","isCorrect":true},{"id":"c","text":"Invoices and shipments are not linked in QB Engineer"},{"id":"d","text":"In the Reports module under Shipment-Invoice Mapping"}],"explanation":"The shipment detail view shows a Linked Invoice field when an invoice has been created for the shipment. The invoice number is a clickable entity link that opens the invoice detail dialog directly."},{"id":"sh10","text":"You need to generate a packing slip to include in a physical package. How do you do this?","options":[{"id":"a","text":"Print the shipment detail page using the browser's print function"},{"id":"b","text":"Generate a Packing Slip PDF from the shipment, which includes the shipment number, customer info, shipping address, and line items with quantities","isCorrect":true},{"id":"c","text":"Packing slips are only available through the Sales Order detail"},{"id":"d","text":"Create a custom report in the Reports module filtered by shipment number"}],"explanation":"Each shipment can generate a Packing Slip PDF. The packing slip includes the shipment number, company information, customer details, shipping address, and a table of all line items with part numbers, descriptions, and quantities. This is designed to be printed and included in the physical package."},{"id":"sh11","text":"The Shipments table shows '---' in the Tracking # column for a shipment. What does this mean?","options":[{"id":"a","text":"The tracking number has been redacted for security"},{"id":"b","text":"No tracking number has been entered for this shipment","isCorrect":true},{"id":"c","text":"The shipment is using a carrier that does not support tracking"},{"id":"d","text":"The tracking number will appear once the shipment status changes to Shipped"}],"explanation":"When no tracking number has been entered, the table displays '---' as a placeholder. The same applies to the Carrier and Shipped Date columns. Tracking numbers can be entered when creating the shipment, or added later via carrier label creation or manual edit."},{"id":"sh12","text":"A shipment is in Shipped status. Which action button is available in the detail view?","options":[{"id":"a","text":"Mark Shipped and Get Rates"},{"id":"b","text":"Mark Delivered (and Track, if a tracking number exists)","isCorrect":true},{"id":"c","text":"Cancel Shipment and Create Invoice"},{"id":"d","text":"No actions — Shipped is a terminal status"}],"explanation":"From Shipped (or In Transit) status, the Mark Delivered button is available. If a tracking number exists and the tracking timeline hasn't been loaded yet, the Track button also appears. Mark Shipped and Get Rates are only available from Pending or Packed status."}]}"""
        });

        Log.Information("Seeded Shipments training modules");
    }
}
